require('dotenv').config({ path: __dirname + '/.env' });
const puppeteer = require('puppeteer-extra');
const StealthPlugin = require('puppeteer-extra-plugin-stealth');
puppeteer.use(StealthPlugin());

const fs = require('fs');
const path = require('path');
const https = require('https');

const COOKIES_PATH = path.join(__dirname, 'cookies.json');
const CACHE_DIR = path.join(__dirname, 'cache');

if (!fs.existsSync(CACHE_DIR)) fs.mkdirSync(CACHE_DIR, { recursive: true });

async function downloadFile(url, dest) {
    return new Promise((resolve, reject) => {
        https.get(url, (response) => {
            if (response.statusCode >= 300 && response.statusCode < 400 && response.headers.location) {
                downloadFile(response.headers.location, dest).then(resolve).catch(reject);
            } else {
                const file = fs.createWriteStream(dest);
                response.pipe(file);
                file.on('finish', () => file.close(resolve));
            }
        }).on('error', (err) => reject(err));
    });
}

function sanitizeName(name) { return name.replace(/[^a-z0-9]/gi, '_').toLowerCase(); }

async function login(browser) {
    const page = await browser.newPage();
    await page.setUserAgent('Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/114.0.0.0 Safari/537.36');
    if (fs.existsSync(COOKIES_PATH)) await page.setCookie(...JSON.parse(fs.readFileSync(COOKIES_PATH)));
    await page.goto('https://sima.unicartagena.edu.co/my/', { waitUntil: 'networkidle2' });
    if (page.url().includes('login/index.php')) {
        await page.type('#username', process.env.SIMA_USER);
        await page.type('#password', process.env.SIMA_PASS);
        await Promise.all([page.click('button[type="submit"]'), page.waitForNavigation()]);
        fs.writeFileSync(COOKIES_PATH, JSON.stringify(await page.cookies(), null, 2));
    }
    return page;
}

async function deepAnalyze(browser, page, courseId, targetUnitId = null) {
    console.log(`🧠 Análisis Stealth: Materia ${courseId} | Unidad ${targetUnitId || 'Todas'}`);
    await page.goto(`https://sima.unicartagena.edu.co/course/view.php?id=${courseId}`, { waitUntil: 'networkidle2' });
    await page.evaluate(() => document.querySelectorAll('.toggle, .section-toggle').forEach(btn => btn.click()));
    await new Promise(r => setTimeout(r, 2000));

    const courseFullName = await page.evaluate(() => document.querySelector('h1.h2')?.innerText.trim() || `materia_${courseId}`);
    const courseSlug = sanitizeName(courseFullName);
    const courseDir = path.join(CACHE_DIR, courseSlug);
    if (!fs.existsSync(courseDir)) fs.mkdirSync(courseDir, { recursive: true });

    const units = await page.evaluate(() => {
        return Array.from(document.querySelectorAll('.course-content li.section'))
        .map(s => {
            const title = s.querySelector('h3, h4')?.innerText.trim() || "General";
            const items = Array.from(s.querySelectorAll('.activity-item a')).map(ai => ({
                name: ai.innerText.trim(),
                url: ai.href,
            })).filter(i => i.name && i.url);
            return { title, items };
        }).filter(s => s.items.length > 0 && (s.title.toLowerCase().includes('unidad') || s.title.toLowerCase().includes('presentación')));
    });

    let finalSummary = "";
    for (const unit of units) {
        const unitNumber = (unit.title.match(/\d+/) || ["TCC"])[0];
        if (targetUnitId && unitNumber !== targetUnitId) continue;
        const unitDir = path.join(courseDir, `Unidad_${unitNumber}`);
        if (!fs.existsSync(unitDir)) fs.mkdirSync(unitDir, { recursive: true });
        const mdFileName = `${courseSlug}_unidad_${unitNumber}_resumen.md`;
        let mdContent = `# ASIGNATURA: ${courseFullName}
# UNIDAD: ${unit.title}

`;
        for (const item of unit.items) {
            if (item.url.includes('/quiz/')) { mdContent += `### ⚠️ EVALUACIÓN BLINDADA: ${item.name}

`; continue; }
            const detailPage = await browser.newPage();
            try {
                await detailPage.goto(item.url, { waitUntil: 'networkidle2' });
                const details = await detailPage.evaluate(() => ({
                    intro: document.querySelector('#intro, .box.py-3')?.innerText.trim() || "Sin descripción.",
                    links: Array.from(document.querySelectorAll('.activity-attachments a, .resource-attachment a')).map(a => ({ name: a.innerText.trim(), url: a.href })).filter(l => l.url),
                }));
                mdContent += `### 📘 ${item.name}
**Enunciado:**
${details.intro}

**Recursos:**
`;
                for (const link of details.links) {
                    if (link.url.includes('.pdf')) {
                        const fileName = sanitizeName(link.name || "recurso") + ".pdf";
                        await downloadFile(link.url, path.join(unitDir, fileName));
                        mdContent += `- 📄 [PDF LOCAL] ${link.name} (./${fileName})
`;
                    } else { mdContent += `- 🔗 [LINK] [${link.name}](${link.url})
`; }
                }
                mdContent += `
---
`;
            } catch (e) {} finally { await detailPage.close(); }
        }
        fs.writeFileSync(path.join(unitDir, mdFileName), mdContent);
        finalSummary = mdContent;
    }
    return { status: "success", course: courseFullName, summary: finalSummary };
}

(async () => {
    try {
        const [,, power, courseId, unitId] = process.argv;
        if (!power) throw new Error("Se requiere un 'poder'");
        const browser = await puppeteer.launch({ headless: "new", args: ['--no-sandbox'] });
